func (c *KafkaConsumer) awsMSKIAMSASLMechanism() (aws.Mechanism, error) {
	if c.config.AssumeRoleARN == "" && c.config.CredentialsProfile == "" {
		return aws.Auth{
			AccessKey: c.config.SASLUser,
			SecretKey: c.config.SASLPassword,
		}.AsManagedStreamingIAMMechanism(), nil
	}

	loadOpts := []func(*awsconfig.LoadOptions) error{}
	if c.config.CredentialsProfile != "" {
		loadOpts = append(loadOpts, awsconfig.WithSharedConfigProfile(c.config.CredentialsProfile))
	}
	if c.config.SASLUser != "" || c.config.SASLPassword != "" {
		loadOpts = append(loadOpts, awsconfig.WithCredentialsProvider(
			credentials.NewStaticCredentialsProvider(c.config.SASLUser, c.config.SASLPassword, ""),
		))
	}

	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()
	awsCfg, err := awsconfig.LoadDefaultConfig(ctx, loadOpts...)
	if err != nil {
		return nil, fmt.Errorf("failed to load AWS config: %w", err)
	}
	if c.config.AssumeRoleARN != "" {
		stsClient := sts.NewFromConfig(awsCfg)
		assumeRoleProvider := stscreds.NewAssumeRoleProvider(stsClient, c.config.AssumeRoleARN)
		awsCfg.Credentials = assumeRoleProvider
	}

	credentialsCache := awsconfig.CredentialsCache(awsCfg)
	return aws.ManagedStreamingIAM(func(ctx context.Context) (aws.Auth, error) {
		creds, err := credentialsCache.Retrieve(ctx)
		if err != nil {
			return aws.Auth{}, err
		}
		return aws.Auth{
			AccessKey:     creds.AccessKeyID,
			SecretKey:     creds.SecretAccessKey,
			SessionToken: creds.SessionToken,
		}, nil
	}), nil
}

